var e=[{id:`L2_1`,type:`dialog`,speaker:`SWORD_OZ_NULL_NULL`,text:{KOREA:`시, 시그마가 순식간에 수영복으로 갈아입었어. 어떻게 한 거지?`,JPN:`し、シグマがあっという間に水着に着替えた。どうやったの？`,ENG:`S-Sigma's suddenly in her swimsuit. How did she do that?`,TWN:`西…西格瑪竟然瞬間換上泳衣，她是怎麼辦到的？`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`그러게. 저 애도 루루 같은 별종인가……?`,JPN:`本当だ。あの子もルルみたいな別種なのかな……？`,ENG:`Y-yeah... Is she another oddball like Lulu...?`,TWN:`這個嘛，難道她和露露一樣身分特殊嗎……？`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SIGMA_RAS_SUMMER_NULL`,text:{KOREA:`오옷! 저기 아빠를 닮은 기계가 있어!`,JPN:`おおっ！　あそこにパパに似てる機械がある！`,ENG:`Ooh, look! That machine looks just like Daddy!`,TWN:`哇喔！那裡有個跟爸爸很像的機器欸！`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_SUMMER_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`아빠를 닮은… 뭐라고?`,JPN:`パパに似た……え？`,ENG:`Looks like your daddy? What?`,TWN:`跟爸爸很像的…什麼？`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`저건 그냥 발리볼 머신일 뿐이야.`,JPN:`あれはただのバレーボールマシンだよ。`,ENG:`That's just the volleyball machine.`,TWN:`那只是排球機器人啦。`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`그냥이 아니지. 지상에서 요즘 핫하다는 모델을 본 떠 만든 세계 최초의 발리볼 머신이라고!`,JPN:`ただのじゃない。地上でもっとも流行ってるっていうモデルを真似して作った、世界最初のバレーボールマシンなんだ！`,ENG:`No, it's not. It's the world's first volleyball machine made to look like a popular model from the ground!`,TWN:`什麼只是，那可是世界第一個排球機器人，是以最近最夯的模型為範本打造的！`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SIGMA_RAS_SUMMER_NULL`,text:{KOREA:`좋아! 친구들을 위해! 아토믹 아빠 퍼니시먼트 나가신다! 요호호!`,JPN:`よし！　友達のために！　アトミック・パパ・パニッシュメントで行くぞ！　ヨホホ！`,ENG:`All right! For all my friends! The Atomic Daddy Punishment is ready for action! Yo ho ho!`,TWN:`很好！爸爸原子懲戒要為朋友挺身而出囉！哇哈哈！`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SIGMA_RAS_SUMMER_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RUNNER_OZ_NULL_NULL`,text:{KOREA:`아토믹…… 뭐?`,JPN:`アトミック……は？`,ENG:`Atomic... what?`,TWN:`原子……啥？`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RUNNER_OZ_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_ROOT`,text:{KOREA:`멋진데……! 왠지 가슴을 울리는 이름이야!`,JPN:`カッコいいなあ……！　なんだか胸が震える名前だよ！`,ENG:`So cool...! That name is giving me goosebumps!`,TWN:`好酷喔……！好撼動人心的名稱！`},stage:{bg:`CLOSE`,bgm:`BATTLE_SUMMER_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HAVEN_HAVEN_NULL_ROOT`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};